let inp = {};
try { inp = $('Birthday Input').first().json || {}; } catch (e) { inp = $input.first().json || {}; }
let admins = [];
try { admins = $('Find BD Requester').all().map(i => i.json).filter(j => j && j.phoneLast10); } catch (e) { admins = []; }

const toPhone = String(inp.toPhone || '').replace(/\D/g, '');
const isAdmin = admins.length > 0;
const isInternal = !toPhone;              // manual / internal caller -> trusted
// The birthday list exposes the WHOLE client base, so only admins may pull it.
const denied = !isInternal && !isAdmin;

var now = new Date();
var mo = parseInt(inp.month, 10);
if (!mo || mo < 1 || mo > 12) { mo = now.getMonth() + 1; }
var page = parseInt(inp.page, 10);
if (!page || page < 1) { page = 1; }
var mm = mo < 10 ? '0' + mo : '' + mo;
var q = denied ? { dob: '__denied_no_match__' } : { dob: { $regex: '-' + mm + '-' } };
var proj = JSON.stringify({ name:1, dob:1, premium:1, sumAssured:1, tableNo:1, term:1, phone:1, phoneLast10:1, groupName:1 });
return [{ json: { collection: 'clients', mongoQuery: JSON.stringify(q), projection: proj, limit: 5000, month: mo, page: page,
  toPhone: toPhone, caption: String(inp.caption || ''), isAdmin: isAdmin, isInternal: isInternal, denied: denied } }];

const meta = $('Route Birthday').first().json;
const rows = $input.all().map(function(i){ return i.json; }).filter(function(j){ return j && Object.keys(j).length > 0; });
const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const FULL = ['January','February','March','April','May','June','July','August','September','October','November','December'];
function num(v){ if (v==null) return 0; var n = parseFloat(String(v).replace(/[^0-9.]/g,'')); return isFinite(n)?n:0; }
function daysUntil(dob){ var p = String(dob).split('-'); if (p.length<3) return 9999; var mo=parseInt(p[1],10), da=parseInt(p[2],10); if(!mo||!da) return 9999; var now=new Date(); var today=new Date(now.getFullYear(),now.getMonth(),now.getDate()); var b=new Date(now.getFullYear(),mo-1,da); if(b<today){ b=new Date(now.getFullYear()+1,mo-1,da);} return Math.round((b-today)/86400000); }
function label(dob){ var p=String(dob).split('-'); var mo=parseInt(p[1],10),da=parseInt(p[2],10); return (da<10?'0'+da:''+da)+' '+(MONTHS[mo-1]||''); }
const byPerson = {};
rows.forEach(function(r){
  var key = (r.phoneLast10 && String(r.phoneLast10)) || (r.name && String(r.name).trim()) || String(r._id);
  if (!byPerson[key]) { byPerson[key] = { name: r.name||'', dob: r.dob||'', phone: r.phoneLast10||r.phone||'', totalPremium: 0, totalCover: 0, policies: 0 }; }
  var p = byPerson[key];
  p.totalPremium += num(r.premium);
  p.totalCover += num(r.sumAssured);
  p.policies += 1;
  if (!p.dob && r.dob) { p.dob = r.dob; }
});
var people = Object.keys(byPerson).map(function(k){ var p=byPerson[k]; return { name:p.name, birthday: label(p.dob), daysUntil: daysUntil(p.dob), phone:p.phone, totalPremium: Math.round(p.totalPremium), totalCover: Math.round(p.totalCover), policies: p.policies }; });
people.sort(function(a,b){ return a.daysUntil - b.daysUntil; });
var total = people.length;
var per = 20;
var page = Math.max(1, parseInt(meta.page||1,10)||1);
var pageCount = Math.ceil(total/per)||1;
var pageItems = people.slice((page-1)*per, (page-1)*per+per);
var THRESH = 200000;
var priority = people.filter(function(p){ return p.totalPremium > THRESH; });
var priorityCapped = priority.slice(0,50);
var monthName = FULL[(meta.month||1)-1] || '';
var teamMessage = '';
if (priority.length) { var names = priorityCapped.map(function(p){ return p.name + ' (' + p.phone + ')'; }).join(', '); teamMessage = 'Please personally call and wish a happy birthday to these high-value CGPE clients, and have a warm conversation with each of them: ' + names + '.'; }
return [{ json: { ok:true, allBirthdays: people, month: monthName, total: total, page: page, pageCount: pageCount, showing: pageItems.length, birthdays: pageItems, priorityCount: priority.length, priorityCallList: priorityCapped, teamMessage: teamMessage, note: 'priorityCallList = clients whose TOTAL premium is above 2 lakh. Term-policy flag not included yet: the client data has no policy-type field.' } }];

const meta = $('Route Birthday').first().json || {};
const f = $('Format Birthday').first().json || {};
const base = { month: f.month, total: f.total };

if (meta.denied) return [{ json: Object.assign({}, base, { denied: true, pdfSent: false, toPhone: '' }) }];
const toPhone = String(meta.toPhone || '');
const people = Array.isArray(f.allBirthdays) ? f.allBirthdays : [];
if (!toPhone || !people.length) {
  return [{ json: Object.assign({}, base, { toPhone: '', pdfSent: false, pdfSkipped: !toPhone ? 'no_toPhone' : 'no_rows' }) }];
}

const cfgRows = $('Load BD Config').all().map(i => i.json);
const cfg = cfgRows[0] || {};
const meta2 = cfg.meta || {};
if (!meta2.token || !meta2.phoneNumberId) return [{ json: Object.assign({}, base, { toPhone: '', pdfSent: false, pdfSkipped: 'no_meta_config' }) }];

const esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c]));
const mmm = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const now = new Date();
const genDate = ('0'+now.getDate()).slice(-2)+' '+mmm[now.getMonth()]+' '+now.getFullYear();
const filename = 'CGPE-Birthdays-' + String(f.month || '').replace(/[^A-Za-z0-9]/g,'') + '.pdf';

const rows = people.map((p, i) =>
  '<tr><td class="n">' + (i+1) + '</td><td>' + esc(p.name) + '</td><td class="b">' + esc(p.birthday) + '</td><td class="p">' + esc(p.phone || '-') + '</td></tr>'
).join('');

const CSS = ':root{--navy:#242C63;--leaf:#82B04F;--forest:#3F7E38;--mist:#F4F8EF;--ink:#20264d;--muted:#6b7392;--line:#E4E8F0}'
 + '*{box-sizing:border-box;margin:0;padding:0}html{-webkit-print-color-adjust:exact;print-color-adjust:exact}'
 + 'body{font-family:Inter,system-ui,Arial,sans-serif;color:var(--ink);font-size:10px;padding:14mm 12mm}'
 + '.hd{display:flex;align-items:center;justify-content:space-between;border-bottom:2px solid var(--leaf);padding-bottom:9px;margin-bottom:12px}'
 + '.hl{display:flex;align-items:center;gap:9px}.lg{width:30px;height:30px;background:center/contain no-repeat}'
 + '.wm{font-family:Georgia,serif;font-weight:800;color:var(--navy);font-size:14px;line-height:1}'
 + '.tag{font-size:7px;letter-spacing:2px;color:var(--leaf);font-weight:700;text-transform:uppercase;margin-top:3px}'
 + '.hr{text-align:right;font-size:8px;color:var(--muted)}.hr b{display:block;color:var(--navy);font-size:9px}'
 + 'h1{font-family:Georgia,serif;font-size:19px;color:var(--navy);margin-bottom:3px}'
 + '.sub{color:var(--muted);font-size:9px;margin-bottom:11px}'
 + 'table{width:100%;border-collapse:collapse;font-size:9px}'
 + 'thead{display:table-header-group}'
 + 'thead th{text-align:left;font-size:7px;letter-spacing:.8px;text-transform:uppercase;color:var(--muted);font-weight:700;padding:0 8px 6px;border-bottom:1.5px solid var(--line)}'
 + 'tbody td{padding:5px 8px;border-bottom:1px solid #EFF2F7;color:#3a4166}'
 + 'tbody tr{page-break-inside:avoid}tbody tr:nth-child(even){background:#FAFBF7}'
 + 'td.n{color:var(--muted);width:26px}td.b{color:var(--forest);font-weight:600;white-space:nowrap}'
 + 'td.p{font-variant-numeric:tabular-nums;white-space:nowrap}'
 + '.ft{margin-top:12px;border-top:1px solid var(--line);padding-top:6px;font-size:7.4px;color:#97a0b8}';

const html = '<!doctype html><html><head><meta charset="utf-8"><title>' + esc(f.month) + ' Birthdays</title><style>' + CSS
 + '.lg{background-image:url(' + "data:image/png;base64," + ')}</style></head><body>'
 + '<div class="hd"><div class="hl"><div class="lg"></div><div><div class="wm">CGP ENTERPRISE</div><div class="tag">Nurturing Wealth, Securing Future</div></div></div>'
 + '<div class="hr"><b>Birthday List</b>Generated ' + genDate + '</div></div>'
 + '<h1>' + esc(f.month) + ' Birthdays</h1>'
 + '<div class="sub">' + f.total + ' clients &middot; sorted by nearest upcoming birthday</div>'
 + '<table><thead><tr><th>#</th><th>Name</th><th>Birthday</th><th>Phone</th></tr></thead><tbody>' + rows + '</tbody></table>'
 + '<div class="ft">Prepared by CGPE from client records &middot; Confidential &mdash; internal use only.</div>'
 + '</body></html>';

try {
  const resp = await this.helpers.request({
    method: 'POST',
    uri: 'http://gotenberg:3000/forms/chromium/convert/html',
    formData: { files: { value: html, options: { filename: 'index.html', contentType: 'text/html' } }, printBackground: 'true', preferCssPageSize: 'false' },
    encoding: null, resolveWithFullResponse: true, simple: false, timeout: 120000,
  });
  const status = resp && resp.statusCode;
  const pdf = Buffer.isBuffer(resp.body) ? resp.body : Buffer.from(resp.body || []);
  if (status !== 200) throw new Error('gotenberg HTTP ' + status + ' :: ' + pdf.toString('utf8').slice(0, 180));
  if (pdf.slice(0,5).toString('latin1') !== '%PDF-') throw new Error('gotenberg non-PDF (' + pdf.length + 'B)');
  const bin = await this.helpers.prepareBinaryData(pdf, filename, 'application/pdf');
  return [{ json: Object.assign({}, base, { toPhone: toPhone, caption: meta.caption || '', filename: filename,
    gv: meta2.graphVersion || 'v20.0', phoneNumberId: meta2.phoneNumberId, token: meta2.token, pdfBytes: pdf.length }), binary: { data: bin } }];
} catch (e) {
  const m = (e && e.message) || ('type=' + typeof e);
  return [{ json: Object.assign({}, base, { toPhone: '', pdfSent: false, pdfStage: 'gotenberg', pdfError: String(m).slice(0,300) }) }];
}

const d = $('Render BD PDF').first().json || {};
const base = { month: d.month, total: d.total };
let up = $('BD Meta Upload').first().json || {};
if (typeof up === 'string') { try { up = JSON.parse(up); } catch (x) {} }
const mediaId = up && up.id;
if (!mediaId) return [{ json: Object.assign({}, base, { pdfSent: false, pdfStage: 'media_upload', pdfError: 'no media id :: ' + JSON.stringify(up).slice(0,220) }) }];
try {
  const resp = await this.helpers.request({
    method: 'POST',
    uri: 'https://graph.facebook.com/' + d.gv + '/' + d.phoneNumberId + '/messages',
    headers: { Authorization: 'Bearer ' + d.token },
    body: { messaging_product: 'whatsapp', to: d.toPhone, type: 'document', document: Object.assign({ id: mediaId, filename: d.filename }, d.caption ? { caption: d.caption } : {}) },
    json: true, resolveWithFullResponse: true, simple: false, timeout: 60000,
  });
  const b = resp && resp.body;
  if (!b || !b.messages) return [{ json: Object.assign({}, base, { pdfSent: false, pdfStage: 'send', pdfError: 'HTTP ' + (resp && resp.statusCode) + ' :: ' + JSON.stringify(b).slice(0,220) }) }];
  return [{ json: Object.assign({}, base, { pdfSent: true, pdfBytes: d.pdfBytes, waMessageId: b.messages[0].id }) }];
} catch (e) {
  return [{ json: Object.assign({}, base, { pdfSent: false, pdfStage: 'send', pdfError: 'throw type=' + typeof e + ' ' + ((e && e.message) || '') }) }];
}

const f = $('Format Birthday').first().json || {};
const r = $('Route Birthday').first().json || {};
if (r.denied) return [{ json: { ok: false, error: 'Only CGPE admins can view the birthday list.' } }];
let s = {};
try { s = $('BD Send Doc').first().json || {}; } catch (e) { try { s = $('Render BD PDF').first().json || {}; } catch (e2) { s = {}; } }
const out = { ok: true, month: f.month, total: f.total, page: f.page, pageCount: f.pageCount, showing: f.showing,
  birthdays: f.birthdays, priorityCount: f.priorityCount, priorityCallList: f.priorityCallList, teamMessage: f.teamMessage,
  pdfSent: !!s.pdfSent, pdfError: s.pdfError || null };
out.note = s.pdfSent
  ? 'The full ' + f.month + ' birthday list PDF (all ' + f.total + ' clients) has ALREADY been delivered to the admin as a WhatsApp document. Reply with a SHORT confirmation in the SAME language the admin is using, mention the month and total, and highlight the high-value clients to call personally. Do NOT paste any link and do NOT list every birthday in the text.'
  : 'No PDF was sent. Format the paginated birthdays list as text as usual.';
return [{ json: out }];
